-- ---------------------------------------------------------- Tabel structuur voor tabel steunnetwerk-- --------------------------------------------------------DROP TABLE IF EXISTS steunnetwerk;CREATE TABLE steunnetwerk (net_id smallint(11) NOT NULL auto_increment,persoon_id smallint(11) NOT NULL default '',net_user_name varchar(20) NOT NULL default '',net_emailadres varchar(35) NOT NULL default '',net_voornaam varchar(20) NOT NULL default 'voornaam',net_achternaam varchar(30) NOT NULL default 'achternaam',net_paswoord varchar(50) NOT NULL default '',net_remote_addr varchar(20) NOT NULL default '',net_confirm_hash varchar(50) NOT NULL default '',net_is_confirmed smallint(4) default NULL,net_date_created date default NULL,net_gebdat date NOT NULL default '0000-00-00',net_gender smallint(3) default NULL,relatietoon smallint(4) default '0',-- 1 Lieve, 2= Beste, 3= Geachterelatietot smallint(4) default '0',-- 0= arts, 1= partner, 2= kind, 3= familie, 4= vriendschap, 5= collega, 6= sport/hobbyrelatiegeeft smallint(4) default NULL,-- geeft energie getal tussen 0 en 10relatiekost smallint(3) default NULL,-- kost energie getal tussen 0 en 10opdehoogte smallint(3) default '0',net_blokkeert smallint(3) default '0',PRIMARY KEY (net_id),KEY persoon_id (persoon_id),KEY net_user_name (net_user_name)) TYPE=MyISAM AUTO_INCREMENT=99 ;-- Gegevens worden uitgevoerd voor tabel steunnetwerkINSERT INTO `steunnetwerk` VALUES (1, 0, 'usernaam', 'email@helpdisk.nl', 'voornaam', 'achternaam', 'pass', '0101010', '', 0, '2006-01-01', '1959-01-27', 0, 1, 1, 0, 0, 1, 0);INSERT INTO `steunnetwerk` VALUES (2, 2, 'Karin2', 'karin@fuzzybrush.nl', 'Karin', 'West', 'passwoord', '', '', 0, '0000-00-00', '1979-01-04', 0, 1, 1, 0, 0, 0, 0);INSERT INTO `steunnetwerk` VALUES (103, 5, 'karin5', 'karin@fuzzybrush.nl', 'karin', 'West', 'passwoord', '', '', 0, '0000-00-00', '1979-01-04', 0, 1, 1, 0, 0, 0, 0);INSERT INTO `steunnetwerk` VALUES (104, 104, 'jonas104', '', 'jonas